import{_ as s,o as a,c as t,e as p}from"./app-83da4608.js";const e={};function o(c,n){return a(),t("div",null,[...n[0]||(n[0]=[p(`<h1 id="_3-4-实时数据处理与流式分析-websocket-异步队列" tabindex="-1"><a class="header-anchor" href="#_3-4-实时数据处理与流式分析-websocket-异步队列" aria-hidden="true">#</a> 3.4 实时数据处理与流式分析（WebSocket, 异步队列）</h1><p>在传统的 HTTP 请求-响应模型中，如果你上传了一份包含 1000 行数据的 CSV 文件给 AI Agent 进行深度分析，这个过程可能需要花费 30 秒甚至更久。在这个过程中，前端只能展示一个单调的 Loading 动画，用户体验极差。</p><p>为了打破这种“黑盒”等待，并支持更现代的 AI 交互体验，我们需要在 <code>ai-data-analyzer/backend</code> 项目中引入<strong>流式分析 (Streaming)</strong>、<strong>实时进度推送 (WebSocket)</strong> 以及<strong>异步任务队列</strong>。</p><hr><h2 id="_1-server-sent-events-sse-与大模型流式响应" tabindex="-1"><a class="header-anchor" href="#_1-server-sent-events-sse-与大模型流式响应" aria-hidden="true">#</a> 1. Server-Sent Events (SSE) 与大模型流式响应</h2><p>当你使用 ChatGPT 时，它的回答是一个字一个字蹦出来的。这背后依赖的是流式传输技术。大语言模型（如 OpenAI、Claude、Ollama）原生都支持流式输出。</p><p>在我们的 NestJS 项目中，如果不使用 WebSocket，最轻量级的流式响应方案是 <strong>SSE (Server-Sent Events)</strong>。</p><h3 id="_1-1-在-llm-service-中支持-stream" tabindex="-1"><a class="header-anchor" href="#_1-1-在-llm-service-中支持-stream" aria-hidden="true">#</a> 1.1 在 LLM Service 中支持 Stream</h3><p>首先，我们需要扩展前面定义的 <code>ILLMService</code>，让它支持返回流。以 OpenAI 为例：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// ai-data-analyzer/backend/src/openai/openai.service.ts</span>
<span class="token keyword">async</span> <span class="token function">chatStream</span><span class="token punctuation">(</span>prompt<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span>AsyncIterable<span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> response <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>openai<span class="token punctuation">.</span>chat<span class="token punctuation">.</span>completions<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
    model<span class="token operator">:</span> <span class="token keyword">this</span><span class="token punctuation">.</span>configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;OPENAI_MODEL&#39;</span><span class="token punctuation">)</span> <span class="token operator">||</span> <span class="token string">&#39;gpt-3.5-turbo&#39;</span><span class="token punctuation">,</span>
    messages<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">{</span> role<span class="token operator">:</span> <span class="token string">&#39;user&#39;</span><span class="token punctuation">,</span> content<span class="token operator">:</span> prompt <span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
    stream<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token comment">// 开启流式输出</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// 将 OpenAI 的 Stream 转换为标准的 AsyncIterable</span>
  <span class="token keyword">return</span> <span class="token punctuation">{</span>
    async <span class="token operator">*</span><span class="token punctuation">[</span>Symbol<span class="token punctuation">.</span>asyncIterator<span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">for</span> <span class="token keyword">await</span> <span class="token punctuation">(</span><span class="token keyword">const</span> chunk <span class="token keyword">of</span> response<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">const</span> content <span class="token operator">=</span> chunk<span class="token punctuation">.</span>choices<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token operator">?.</span>delta<span class="token operator">?.</span>content<span class="token punctuation">;</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>content<span class="token punctuation">)</span> <span class="token punctuation">{</span>
          <span class="token keyword">yield</span> content<span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-在-controller-中使用-sse-装饰器" tabindex="-1"><a class="header-anchor" href="#_1-2-在-controller-中使用-sse-装饰器" aria-hidden="true">#</a> 1.2 在 Controller 中使用 @Sse 装饰器</h3><p>NestJS 提供了 <code>@Sse</code> 装饰器，专门用于处理 Server-Sent Events：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// ai-data-analyzer/backend/src/analysis/analysis.controller.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Controller<span class="token punctuation">,</span> Post<span class="token punctuation">,</span> Body<span class="token punctuation">,</span> Sse<span class="token punctuation">,</span> MessageEvent <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/common&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Observable <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;rxjs&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Controller</span></span><span class="token punctuation">(</span><span class="token string">&#39;analysis&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisController</span> <span class="token punctuation">{</span>
  
  <span class="token decorator"><span class="token at operator">@</span><span class="token function">Post</span></span><span class="token punctuation">(</span><span class="token string">&#39;stream&#39;</span><span class="token punctuation">)</span>
  <span class="token decorator"><span class="token at operator">@</span><span class="token function">Sse</span></span><span class="token punctuation">(</span><span class="token string">&#39;stream&#39;</span><span class="token punctuation">)</span> <span class="token comment">// 将该接口标记为 SSE 路由</span>
  <span class="token keyword">async</span> <span class="token function">streamAnalysis</span><span class="token punctuation">(</span><span class="token decorator"><span class="token at operator">@</span><span class="token function">Body</span></span><span class="token punctuation">(</span><span class="token string">&#39;prompt&#39;</span><span class="token punctuation">)</span> prompt<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span>Observable<span class="token operator">&lt;</span>MessageEvent<span class="token operator">&gt;&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> stream <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>llmService<span class="token punctuation">.</span><span class="token function">chatStream</span><span class="token punctuation">(</span>prompt<span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Observable</span><span class="token punctuation">(</span><span class="token punctuation">(</span>subscriber<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
      <span class="token punctuation">(</span><span class="token keyword">async</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
        <span class="token keyword">try</span> <span class="token punctuation">{</span>
          <span class="token keyword">for</span> <span class="token keyword">await</span> <span class="token punctuation">(</span><span class="token keyword">const</span> chunk <span class="token keyword">of</span> stream<span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">// 不断向前端推送数据块</span>
            subscriber<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">{</span> data<span class="token operator">:</span> chunk <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
          <span class="token punctuation">}</span>
          subscriber<span class="token punctuation">.</span><span class="token function">complete</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span>err<span class="token punctuation">)</span> <span class="token punctuation">{</span>
          subscriber<span class="token punctuation">.</span><span class="token function">error</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
      <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>前端只需要使用浏览器原生的 <code>EventSource</code> API，或者在 Fetch API 中解析 <code>ReadableStream</code>，即可实现打字机效果。</p><hr><h2 id="_2-websocket-双向通信-agent-执行进度汇报" tabindex="-1"><a class="header-anchor" href="#_2-websocket-双向通信-agent-执行进度汇报" aria-hidden="true">#</a> 2. WebSocket 双向通信：Agent 执行进度汇报</h2><p>SSE 只能实现单向（服务端到客户端）的文本流，但我们的 AI Agent 往往包含多个步骤（如：1. 理解意图 -&gt; 2. 读取数据 -&gt; 3. 执行工具 -&gt; 4. 总结结果）。</p><p>对于这种复杂的交互，使用 WebSocket 进行双向通信是更好的选择。</p><p>在 NestJS 中集成 WebSocket 非常优雅，我们可以使用 <code>@nestjs/websockets</code> 和 <code>socket.io</code>。</p><h3 id="_2-1-创建-websocket-gateway" tabindex="-1"><a class="header-anchor" href="#_2-1-创建-websocket-gateway" aria-hidden="true">#</a> 2.1 创建 WebSocket Gateway</h3><p>我们可以创建一个专门的网关来处理与前端的实时连接：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// ai-data-analyzer/backend/src/analysis/analysis.gateway.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> WebSocketGateway<span class="token punctuation">,</span> WebSocketServer<span class="token punctuation">,</span> SubscribeMessage<span class="token punctuation">,</span> MessageBody <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/websockets&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Server <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;socket.io&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> AnalysisService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./analysis.service&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">WebSocketGateway</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> cors<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> namespace<span class="token operator">:</span> <span class="token string">&#39;/agent&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisGateway</span> <span class="token punctuation">{</span>
  <span class="token decorator"><span class="token at operator">@</span><span class="token function">WebSocketServer</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span>
  server<span class="token operator">:</span> Server<span class="token punctuation">;</span>

  <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token keyword">private</span> <span class="token keyword">readonly</span> analysisService<span class="token operator">:</span> AnalysisService<span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

  <span class="token decorator"><span class="token at operator">@</span><span class="token function">SubscribeMessage</span></span><span class="token punctuation">(</span><span class="token string">&#39;start_analysis&#39;</span><span class="token punctuation">)</span>
  <span class="token keyword">async</span> <span class="token function">handleStartAnalysis</span><span class="token punctuation">(</span><span class="token decorator"><span class="token at operator">@</span><span class="token function">MessageBody</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> payload<span class="token operator">:</span> <span class="token punctuation">{</span> data<span class="token operator">:</span> <span class="token builtin">any</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span> prompt<span class="token operator">:</span> <span class="token builtin">string</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span><span class="token keyword">void</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> <span class="token punctuation">{</span> data<span class="token punctuation">,</span> prompt <span class="token punctuation">}</span> <span class="token operator">=</span> payload<span class="token punctuation">;</span>
    
    <span class="token comment">// 模拟 Agent 的多步执行过程，并实时向前端发送进度</span>
    
    <span class="token keyword">this</span><span class="token punctuation">.</span>server<span class="token punctuation">.</span><span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;agent_progress&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> step<span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">,</span> message<span class="token operator">:</span> <span class="token string">&#39;接收到任务，正在清洗数据...&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">const</span> cleanData <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisService<span class="token punctuation">.</span><span class="token function">preprocessPayload</span><span class="token punctuation">(</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token keyword">this</span><span class="token punctuation">.</span>server<span class="token punctuation">.</span><span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;agent_progress&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> step<span class="token operator">:</span> <span class="token number">2</span><span class="token punctuation">,</span> message<span class="token operator">:</span> <span class="token string">&#39;数据清洗完成，正在请求大模型...&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 假设这里的 analyzeData 被改造成了支持回调或事件的方式</span>
    <span class="token keyword">const</span> result <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisService<span class="token punctuation">.</span><span class="token function">analyzeData</span><span class="token punctuation">(</span>cleanData<span class="token punctuation">,</span> prompt<span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token keyword">this</span><span class="token punctuation">.</span>server<span class="token punctuation">.</span><span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;agent_progress&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> step<span class="token operator">:</span> <span class="token number">3</span><span class="token punctuation">,</span> message<span class="token operator">:</span> <span class="token string">&#39;分析完成！&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">this</span><span class="token punctuation">.</span>server<span class="token punctuation">.</span><span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;agent_result&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> result <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>前端只需要连接 <code>ws://localhost:3001/agent</code>，并监听 <code>agent_progress</code> 事件，就能渲染出一个非常直观的“任务执行进度条”，极大地缓解了用户的等待焦虑。</p><h2 id="_3-异步任务队列与微服务-microservices" tabindex="-1"><a class="header-anchor" href="#_3-异步任务队列与微服务-microservices" aria-hidden="true">#</a> 3. 异步任务队列与微服务 (Microservices)</h2><p>当数据量极大（例如用户上传了 10MB 的 CSV），或者平台同时涌入大量用户的分析请求时，单体 NestJS 服务器很容易因为长耗时的计算或 API 等待而被阻塞，导致其他用户的请求无响应。</p><p><strong>解决方案是将耗时任务放入消息队列，实现异步处理和削峰填谷。</strong></p><h3 id="_3-1-引入-bullmq-和-redis" tabindex="-1"><a class="header-anchor" href="#_3-1-引入-bullmq-和-redis" aria-hidden="true">#</a> 3.1 引入 BullMQ 和 Redis</h3><p>在 NestJS 中，最常用的任务队列方案是基于 Redis 的 <code>@nestjs/bullmq</code>。</p><p>安装依赖后，我们可以在模块中配置队列：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token keyword">import</span> <span class="token punctuation">{</span> BullModule <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/bullmq&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Module</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  imports<span class="token operator">:</span> <span class="token punctuation">[</span>
    BullModule<span class="token punctuation">.</span><span class="token function">forRoot</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
      connection<span class="token operator">:</span> <span class="token punctuation">{</span>
        host<span class="token operator">:</span> <span class="token string">&#39;localhost&#39;</span><span class="token punctuation">,</span>
        port<span class="token operator">:</span> <span class="token number">6379</span><span class="token punctuation">,</span>
      <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    BullModule<span class="token punctuation">.</span><span class="token function">registerQueue</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
      name<span class="token operator">:</span> <span class="token string">&#39;analysis-queue&#39;</span><span class="token punctuation">,</span> <span class="token comment">// 注册一个名为 analysis-queue 的队列</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token punctuation">]</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisModule</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-生产者-producer-将任务丢入队列" tabindex="-1"><a class="header-anchor" href="#_3-2-生产者-producer-将任务丢入队列" aria-hidden="true">#</a> 3.2 生产者 (Producer)：将任务丢入队列</h3><p>当用户通过 HTTP 接口上传文件并请求分析时，我们不再同步等待结果，而是将任务推入队列，并立即返回一个 <code>taskId</code> 给前端：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token decorator"><span class="token at operator">@</span><span class="token function">Controller</span></span><span class="token punctuation">(</span><span class="token string">&#39;analysis&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisController</span> <span class="token punctuation">{</span>
  <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token decorator"><span class="token at operator">@</span><span class="token function">InjectQueue</span></span><span class="token punctuation">(</span><span class="token string">&#39;analysis-queue&#39;</span><span class="token punctuation">)</span> <span class="token keyword">private</span> analysisQueue<span class="token operator">:</span> Queue<span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

  <span class="token decorator"><span class="token at operator">@</span><span class="token function">Post</span></span><span class="token punctuation">(</span><span class="token string">&#39;upload-async&#39;</span><span class="token punctuation">)</span>
  <span class="token keyword">async</span> <span class="token function">uploadAndAnalyzeAsync</span><span class="token punctuation">(</span><span class="token decorator"><span class="token at operator">@</span><span class="token function">Body</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> payload<span class="token operator">:</span> <span class="token builtin">any</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 1. 将数据和 prompt 推入队列</span>
    <span class="token keyword">const</span> job <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisQueue<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;analyze-job&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
      data<span class="token operator">:</span> payload<span class="token punctuation">.</span>data<span class="token punctuation">,</span>
      prompt<span class="token operator">:</span> payload<span class="token punctuation">.</span>prompt
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 2. 立即响应，告知前端任务已受理</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span> 
      message<span class="token operator">:</span> <span class="token string">&#39;分析任务已提交&#39;</span><span class="token punctuation">,</span> 
      taskId<span class="token operator">:</span> job<span class="token punctuation">.</span>id 
    <span class="token punctuation">}</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-3-消费者-consumer-后台异步处理" tabindex="-1"><a class="header-anchor" href="#_3-3-消费者-consumer-后台异步处理" aria-hidden="true">#</a> 3.3 消费者 (Consumer)：后台异步处理</h3><p>然后我们创建一个 Processor 来专门在后台监听队列并执行分析逻辑：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token keyword">import</span> <span class="token punctuation">{</span> Processor<span class="token punctuation">,</span> WorkerHost <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/bullmq&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Job <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;bullmq&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Processor</span></span><span class="token punctuation">(</span><span class="token string">&#39;analysis-queue&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisProcessor</span> <span class="token keyword">extends</span> <span class="token class-name">WorkerHost</span> <span class="token punctuation">{</span>
  <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token keyword">private</span> <span class="token keyword">readonly</span> analysisService<span class="token operator">:</span> AnalysisService<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">super</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token keyword">async</span> <span class="token function">process</span><span class="token punctuation">(</span>job<span class="token operator">:</span> Job<span class="token operator">&lt;</span><span class="token builtin">any</span><span class="token punctuation">,</span> <span class="token builtin">any</span><span class="token punctuation">,</span> <span class="token builtin">string</span><span class="token operator">&gt;</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span><span class="token builtin">any</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">正在处理任务: </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>job<span class="token punctuation">.</span>id<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">const</span> <span class="token punctuation">{</span> data<span class="token punctuation">,</span> prompt <span class="token punctuation">}</span> <span class="token operator">=</span> job<span class="token punctuation">.</span>data<span class="token punctuation">;</span>
    
    <span class="token comment">// 执行真正的耗时分析逻辑</span>
    <span class="token keyword">const</span> result <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisService<span class="token punctuation">.</span><span class="token function">analyzeData</span><span class="token punctuation">(</span>data<span class="token punctuation">,</span> prompt<span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 处理完成后，可以将结果存入数据库 (AnalysisResultEntity)，</span>
    <span class="token comment">// 或者通过上文提到的 WebSocket 主动推送给前端</span>
    <span class="token keyword">return</span> result<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-4-架构演进-微服务拆分" tabindex="-1"><a class="header-anchor" href="#_3-4-架构演进-微服务拆分" aria-hidden="true">#</a> 3.4 架构演进：微服务拆分</h3><p>当业务进一步扩大，这个负责消费队列的 <code>AnalysisProcessor</code> 甚至可以被抽离成一个独立的 NestJS 微服务。</p><p>你可以启动 1 个专门处理 HTTP 请求的 API 服务，同时在后台启动 5 个运行着 <code>AnalysisProcessor</code> 的 Worker 服务来并行消费 Redis 队列中的分析任务。这就是标准的企业级<strong>高并发异步处理架构</strong>。</p><hr><h2 id="_4-测试与验证" tabindex="-1"><a class="header-anchor" href="#_4-测试与验证" aria-hidden="true">#</a> 4. 测试与验证</h2><p>在完成了 SSE、WebSocket 和 异步队列的代码集成后，我们可以通过以下步骤进行测试验证。</p><h3 id="_4-1-环境准备" tabindex="-1"><a class="header-anchor" href="#_4-1-环境准备" aria-hidden="true">#</a> 4.1 环境准备</h3><p>在使用异步队列功能前，你需要确保本地运行了 Redis。如果你安装了 Docker，可以通过以下命令快速启动一个本地 Redis：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">--name</span> my-redis <span class="token parameter variable">-p</span> <span class="token number">6379</span>:6379 <span class="token parameter variable">-d</span> redis
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>启动后端服务：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">pnpm</span> run start:dev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_4-2-测试-1-验证-sse-流式输出" tabindex="-1"><a class="header-anchor" href="#_4-2-测试-1-验证-sse-流式输出" aria-hidden="true">#</a> 4.2 测试 1：验证 SSE 流式输出</h3><p>SSE 接口可以直接通过 <code>cURL</code> 测试，观察终端中字符是不是一段一段地输出：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> <span class="token parameter variable">-N</span> <span class="token string">&quot;http://localhost:3001/analysis/stream?prompt=test&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><em>注意：<code>-N</code> 参数告诉 curl 不要缓冲输出，从而能看到实时的打字机效果。</em></p><h3 id="_4-3-测试-2-验证-websocket-连接" tabindex="-1"><a class="header-anchor" href="#_4-3-测试-2-验证-websocket-连接" aria-hidden="true">#</a> 4.3 测试 2：验证 WebSocket 连接</h3><p>为了测试 WebSocket，你可以使用浏览器控制台。打开任意一个网页，按下 <code>F12</code>，在 Console 中输入以下代码：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 引入 socket.io 客户端脚本</span>
<span class="token keyword">const</span> script <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">createElement</span><span class="token punctuation">(</span><span class="token string">&#39;script&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
script<span class="token punctuation">.</span>src <span class="token operator">=</span> <span class="token string">&quot;https://cdn.socket.io/4.7.2/socket.io.min.js&quot;</span><span class="token punctuation">;</span>
document<span class="token punctuation">.</span>head<span class="token punctuation">.</span><span class="token function">appendChild</span><span class="token punctuation">(</span>script<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 必须等待脚本加载完毕再执行后续逻辑！</span>
script<span class="token punctuation">.</span><span class="token function-variable function">onload</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;Socket.io script loaded!&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  
  <span class="token comment">// 连接 WebSocket 服务</span>
  <span class="token keyword">const</span> socket <span class="token operator">=</span> <span class="token function">io</span><span class="token punctuation">(</span><span class="token string">&#39;ws://localhost:3001/agent&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// 监听连接成功事件</span>
  socket<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;connect&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;Connected to WebSocket server&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 发起分析请求</span>
    socket<span class="token punctuation">.</span><span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;start_analysis&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">prompt</span><span class="token operator">:</span> <span class="token string">&quot;计算 100 + 200 的结果&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// 监听进度事件</span>
  socket<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;agent_progress&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">data</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">[进度更新] 步骤 </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>data<span class="token punctuation">.</span>step<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">: </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>data<span class="token punctuation">.</span>message<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// 监听结果事件</span>
  socket<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;agent_result&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">data</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">[最终结果]:</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span> data<span class="token punctuation">.</span>result<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>你会看到控制台依次打印出“接收到任务”、“正在请求大模型”以及最终的分析结果。</p><h3 id="_4-4-测试-3-验证-bullmq-异步队列" tabindex="-1"><a class="header-anchor" href="#_4-4-测试-3-验证-bullmq-异步队列" aria-hidden="true">#</a> 4.4 测试 3：验证 BullMQ 异步队列</h3><p>你可以向异步上传接口发送一个 POST 请求：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> <span class="token parameter variable">-X</span> POST http://localhost:3001/analysis/upload-async <span class="token punctuation">\\</span>
  <span class="token parameter variable">-H</span> <span class="token string">&quot;Content-Type: application/json&quot;</span> <span class="token punctuation">\\</span>
  <span class="token parameter variable">-d</span> <span class="token string">&#39;{
    &quot;prompt&quot;: &quot;分析这批数据&quot;,
    &quot;data&quot;: [{&quot;id&quot;: 1, &quot;value&quot;: 100}, {&quot;id&quot;: 2, &quot;value&quot;: 200}]
  }&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>你会立刻收到一个类似于 <code>{&quot;message&quot;:&quot;分析任务已提交&quot;,&quot;taskId&quot;:&quot;1&quot;}</code> 的响应，请求没有被阻塞。</p><p>同时，观察后端控制台的日志，你会看到 <code>AnalysisProcessor</code> 在后台默默消费了这个任务：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[AnalysisProcessor] 正在处理后台分析任务: 1
[AnalysisService] Analyzing text: 分析这批数据
数据内容: [{&quot;id&quot;:1,&quot;value&quot;:100},{&quot;id&quot;:2,&quot;value&quot;:200}]...
[AnalysisProcessor] 任务 1 处理完成
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="_5-开发体验优化-解决端口占用问题-eaddrinuse" tabindex="-1"><a class="header-anchor" href="#_5-开发体验优化-解决端口占用问题-eaddrinuse" aria-hidden="true">#</a> 5. 开发体验优化：解决端口占用问题 (EADDRINUSE)</h2><p>在实际开发过程中，尤其是在使用 <code>start:dev</code> 进行热更新重启时，经常会遇到旧进程未能及时释放端口，导致新的进程启动失败并报错 <code>Error: listen EADDRINUSE: address already in use :::3001</code> 的问题。这会严重打断开发心流。</p><p>为了实现更自动化的开发体验，我们可以引入 <code>kill-port</code> 工具，在每次启动前自动清理残留进程。</p><h3 id="_5-1-安装工具" tabindex="-1"><a class="header-anchor" href="#_5-1-安装工具" aria-hidden="true">#</a> 5.1 安装工具</h3><p>首先，在后端项目中安装 <code>kill-port</code> 作为开发依赖：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">pnpm</span> <span class="token function">add</span> <span class="token parameter variable">-D</span> kill-port
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_5-2-改造-package-json-启动脚本" tabindex="-1"><a class="header-anchor" href="#_5-2-改造-package-json-启动脚本" aria-hidden="true">#</a> 5.2 改造 package.json 启动脚本</h3><p>然后，修改 <code>package.json</code> 中的 <code>scripts</code> 节点，在启动 NestJS 服务前加入清理端口的逻辑。为了防止因为端口本来就没被占用而导致命令失败退出，我们需要加上 <code>|| true</code>。</p><p>修改后的脚本如下：</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;scripts&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token property">&quot;start&quot;</span><span class="token operator">:</span> <span class="token string">&quot;kill-port 3001 || true &amp;&amp; nest start&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;start:dev&quot;</span><span class="token operator">:</span> <span class="token string">&quot;kill-port 3001 || true &amp;&amp; nest start --watch&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;start:debug&quot;</span><span class="token operator">:</span> <span class="token string">&quot;kill-port 3001 || true &amp;&amp; nest start --debug --watch&quot;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-3-测试自动化重启效果" tabindex="-1"><a class="header-anchor" href="#_5-3-测试自动化重启效果" aria-hidden="true">#</a> 5.3 测试自动化重启效果</h3><p><strong>测试步骤：</strong></p><ol><li>正常运行 <code>pnpm run start:dev</code>，让服务在 3001 端口跑起来。</li><li>此时如果你新开一个终端窗口，强行再次运行 <code>pnpm run start:dev</code>，原本会立刻报错 <code>EADDRINUSE</code>。</li><li>但在优化后，你会看到终端首先输出 <code>Process on port 3001 killed</code>（杀死了旧进程），紧接着新的 NestJS 实例顺利启动，显示 <code>API listening on http://localhost:3001</code>。</li></ol><p><strong>实际效果：</strong> 以后不论是因为什么原因导致的异常退出，或者频繁保存代码触发的热更新，你都不需要再手动执行 <code>lsof -i :3001</code> 和 <code>kill -9</code> 去清理僵尸进程了，极大提升了本地开发的流畅度。</p><hr><p>下一节，我们将讨论如何保证进入和输出系统的数据质量。</p>`,78)])])}const i=s(e,[["render",o],["__file","3.4 实时数据处理与流式分析（WebSocket_ Microservices）.html.vue"]]);export{i as default};
